import { generateVietQR, getBankByBin, getBankByShortName, sanitizeAccountName } from '@viet-qr/core';
import QRCode from 'qrcode';

export class VietQRPayStandee extends HTMLElement {
  static get observedAttributes() {
    return [
      'bank-id',
      'account-no',
      'account-name',
      'amount',
      'content',
      'size',
      'title',
      'subtitle',
      'theme'
    ];
  }

  private qrContainer: HTMLElement | null = null;
  private titleH2: HTMLHeadingElement | null = null;
  private subtitleP: HTMLParagraphElement | null = null;
  private nameH3: HTMLHeadingElement | null = null;
  private accountP: HTMLParagraphElement | null = null;
  private bankP: HTMLParagraphElement | null = null;

  constructor() {
    super();
  }

  connectedCallback() {
    this.renderInitial();
    this.updateData();
  }

  attributeChangedCallback() {
    this.updateData();
  }

  private renderInitial() {
    const theme = this.getAttribute('theme') || 'light';
    
    this.innerHTML = `
      <div class="vqr-pay-standee vqr-theme-${theme}" id="standee-wrapper">
        <div class="vqr-pay-standee__banner">
          <h2 class="vqr-pay-standee__title" id="standee-title"></h2>
          <p class="vqr-pay-standee__subtitle" id="standee-subtitle"></p>
        </div>

        <div class="vqr-pay-standee__body">
          <div class="vqr-pay-standee__qr-wrapper" id="qr-container">
          </div>

          <div class="vqr-pay-standee__info">
            <h3 class="vqr-pay-standee__name" id="standee-name" style="display: none;"></h3>
            <p class="vqr-pay-standee__account" id="standee-account"></p>
            <p class="vqr-pay-standee__bank" id="standee-bank"></p>
          </div>
        </div>
      </div>
    `;

    this.qrContainer = this.querySelector('#qr-container');
    this.titleH2 = this.querySelector('#standee-title');
    this.subtitleP = this.querySelector('#standee-subtitle');
    this.nameH3 = this.querySelector('#standee-name');
    this.accountP = this.querySelector('#standee-account');
    this.bankP = this.querySelector('#standee-bank');
  }

  private async updateData() {
    if (!this.qrContainer) return; // Not mounted yet

    const bankId = this.getAttribute('bank-id') || '';
    const accountNo = this.getAttribute('account-no') || '';
    const accountName = this.getAttribute('account-name') || '';
    const amountStr = this.getAttribute('amount');
    const amount = amountStr ? parseInt(amountStr, 10) : undefined;
    const content = this.getAttribute('content') || '';
    const size = parseInt(this.getAttribute('size') || '200', 10);
    const title = this.getAttribute('title') || 'Quét mã để thanh toán';
    const subtitle = this.getAttribute('subtitle') || 'Hỗ trợ ứng dụng ngân hàng & ví điện tử';
    const theme = this.getAttribute('theme') || 'light';

    const wrapper = this.querySelector('#standee-wrapper');
    if (wrapper) {
      wrapper.className = `vqr-pay-standee vqr-theme-${theme}`;
    }

    if (this.titleH2) this.titleH2.textContent = title;
    if (this.subtitleP) this.subtitleP.textContent = subtitle;

    const bankInfo = getBankByBin(bankId) || getBankByShortName(bankId);
    const bankName = bankInfo?.shortName || bankId;

    if (this.nameH3) {
      if (accountName) {
        this.nameH3.textContent = sanitizeAccountName(accountName);
        this.nameH3.style.display = 'block';
      } else {
        this.nameH3.style.display = 'none';
      }
    }

    if (this.accountP) this.accountP.textContent = accountNo;
    if (this.bankP) this.bankP.textContent = `Ngân hàng ${bankName}`;

    if (bankId && accountNo) {
      try {
        const payload = generateVietQR({ bankId, accountNo, accountName, amount, content });
        const svgString = await QRCode.toString(payload, {
          type: 'svg',
          width: size,
          margin: 1,
          color: {
            dark: '#000000',
            light: '#ffffff'
          }
        });
        this.qrContainer.innerHTML = svgString;
      } catch (err) {
        console.error('Failed to generate VietQR:', err);
        this.qrContainer.innerHTML = '<p style="color: red;">Invalid QR Data</p>';
      }
    }
  }
}
